# OEIS sequence: A333964

from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, prevprime, nextprime
def A333964_gen(): # generator of terms if the first n terms are desired.
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        for p in ps:
            if p == 2 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        if len(ps)<4:
            mp = m*nextprime(max(ps.keys(),default=1))
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A333964_list = list(islice(A333964_gen(),40)) # _Chai Wah Wu_, Mar 27 2026

